INSERT INTO member (
    mem_number, mem_pwd, mem_name, mem_sex, role_id, mem_state
) VALUES (
             #{memNumber}, #{memPwd}, #{memName}, #{memSex}, #{roleId}, #{memState}
         )

INSERT INTO neps_feedback (
    member_id, phone_number, province_id, city_id,
    specific_address, aqi_level, air_quality_description, remarks
) VALUES (
             #{memberId}, #{phoneNumber}, #{provinceId}, #{cityId},
             #{specificAddress}, #{aqiLevel}, #{airQualityDescription}, #{remarks}
         )
